1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return an empty array when given an empty input (no live cells)", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	
9	  it("should kill a single isolated live cell — [(0,0)] becomes []", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	
13	  it("should kill two adjacent live cells with only 1 neighbor each (Rule 1 Underpopulation) — [(0,1), (1,1)] becomes []", () => {
14	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
15	  });
16	
17	  it("should bring a dead cell with exactly 3 live neighbors to life (Rule 4 Reproduction) — L-shape [(0,2), (1,2), (0,1)] produces square including (1,1)", () => {
18	    const result = nextGeneration([[0, 2], [1, 2], [0, 1]]);
19	    expect(result).toHaveLength(4);
20	    expect(result).toEqual(expect.arrayContaining<Cell>([[0, 2], [1, 2], [0, 1], [1, 1]]));
21	  });
22	
23	  it("should keep a live cell alive when it has 3 live neighbors (Rule 2 Survival) — top row ### plus (1,-1) → center (1,1) survives", () => {
24	    const result = nextGeneration([[0, 2], [1, 2], [2, 2], [1, 1]]);
25	    expect(result).toEqual(expect.arrayContaining<Cell>([[1, 1]]));
26	  });
27	
28	  it.todo("should kill a live cell with 4 live neighbors (Rule 3 Overpopulation) — full 3x3 minus middle row sides: center (1,1) dies");
29	
30	  it.todo("should keep a 2x2 block unchanged across generations (Block still life) — [(0,0), (1,0), (0,1), (1,1)] stays the same");
31	
32	  it.todo("should oscillate a vertical blinker to a horizontal blinker — [(0,0), (0,1), (0,2)] becomes [(-1,1), (0,1), (1,1)]");
33	
34	  it.todo("should handle negative coordinates correctly — blinker at negative origin oscillates as expected");
35	});
36

1	export type Cell = [number, number];
2	
3	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	const survives = (isAlive: boolean, neighborCount: number): boolean =>
12	  isAlive ? neighborCount === 2 || neighborCount === 3 : neighborCount === 3;
13	
14	export function nextGeneration(cells: Array<Cell>): Array<Cell> {
15	  const liveSet = new Set(cells.map(keyOf));
16	
17	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const neighbor: Cell = [x + dx, y + dy];
21	      const k = keyOf(neighbor);
22	      const entry = neighborCounts.get(k);
23	      if (entry) entry.count += 1;
24	      else neighborCounts.set(k, { cell: neighbor, count: 1 });
25	    }
26	  }
27	
28	  const result: Array<Cell> = [];
29	  for (const [k, { cell, count }] of neighborCounts) {
30	    if (survives(liveSet.has(k), count)) result.push(cell);
31	  }
32	  return result;
33	}
