it("should kill a live cell with 4 live neighbors (Rule 3 Overpopulation) — full 3x3 minus middle row sides: center (1,1) dies", () => {
  const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]]);
